import{_ as n,o as r,c as t,a7 as a}from"./chunks/framework.BgApuQ2e.js";const o="/images/american-presidents-johnson-mckinley/clickbait2.png",s="/images/american-presidents-johnson-mckinley/PartyVotes-Presidents.png",i="/images/american-presidents-johnson-mckinley/Mustache.png",l="/images/american-presidents-johnson-mckinley/Johnson.png",p="/images/american-presidents-johnson-mckinley/pinit_fg_en_rect_gray_20.png",w=JSON.parse('{"title":"The American Presidents—Johnson to McKinley","description":"","frontmatter":{"title":"The American Presidents—Johnson to McKinley","titleZh":"美国总统——从Johnson到McKinley","date":"2015-02-20T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html","slug":"american-presidents-johnson-mckinley"},"headers":[],"relativePath":"posts/american-presidents-johnson-mckinley.md","filePath":"posts/american-presidents-johnson-mckinley.md","lastUpdated":1782886257000}'),h={name:"posts/american-presidents-johnson-mckinley.md"};function m(c,e,g,d,y,k){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="美国总统——从johnson到mckinley-·-the-american-presidents—johnson-to-mckinley" tabindex="-1">美国总统——从Johnson到McKinley · The American Presidents—Johnson to McKinley <a class="header-anchor" href="#美国总统——从johnson到mckinley-·-the-american-presidents—johnson-to-mckinley" aria-label="Permalink to &quot;美国总统——从Johnson到McKinley · The American Presidents—Johnson to McKinley&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html</a> · 2015-02-20</p></blockquote><h2 id="注-这是第-2-部分。第-1-部分-华盛顿到林肯-在这里。" tabindex="-1"><em><strong>注:</strong> 这是第 2 部分。第 1 部分(华盛顿到林肯)在<a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html" target="_blank" rel="noreferrer">这里</a>。</em> <a class="header-anchor" href="#注-这是第-2-部分。第-1-部分-华盛顿到林肯-在这里。" aria-label="Permalink to &quot;***注:** 这是第 2 部分。第 1 部分(华盛顿到林肯)在[这里](https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html)。*&quot;">​</a></h2><p>去年,我发布了那篇《<a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html" target="_blank" rel="noreferrer">美国总统——华盛顿到林肯</a>》。</p><p>从华盛顿到林肯。两位超级巨星,中间夹着亚当斯、杰斐逊、麦迪逊、杰克逊这样的传奇人物;宪法的诞生;从东海岸 13 个殖民地扩张成一个横跨大西洋到太平洋的庞大国家;两场对外战争;还有围绕奴隶制问题的激烈辩论——所有这一切,最终燃向内战这个火爆的高潮和奴隶制的废除。这题材不是每个人都爱看——但如果我在 Facebook 上看到这标题,我肯定会疯狂点击。</p><p>今年,我走了一条不一样的路。我创造出了 <em>互联网史上最没有点击欲的标题之一</em>。</p><p>完整的画风大概是这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/02/clickbait2.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt="clickbait"></a></p><p>所以请原谅我有点困惑,为什么你现在会在这里——为什么你会自愿把自己扔进一篇聚焦于安德鲁·约翰逊 (Andrew Johnson)、尤利西斯·S·格兰特 (Ulysses S. Grant)、拉瑟福德·B·海斯 (Rutherford B. Hayes)、詹姆斯·A·加菲尔德 (James A. Garfield)、切斯特·A·阿瑟 (Chester A. Arthur)、格罗弗·克利夫兰 (Grover Cleveland)、本杰明·哈里森 (Benjamin Harrison) 和威廉·麦金利 (William McKinley) 的文章里。</p><p>也许你是在试图点「隐藏所有 Wait But Why 的帖子」时不小心点进来的。或者,也许——只是也许——你和我一样,对这群 <em>连续八位没人听说过的总统</em> 有一种病态的迷恋。当然,你对格兰特略知一二。你知道约翰逊被弹劾过。你可能知道加菲尔德和麦金利遇刺了。但除非你是历史迷,不然你知道的也就这么多。我算挺喜欢历史的,而我知道的也就这么多。</p><p>所以我决定挖一挖——比我挖前 16 位总统挖得深多了——去挖林肯和西奥多·罗斯福之间的这个深渊。因为如果我们要做这件事,那我们就得真做。</p><p>开始之前先说三点:</p><p><strong>1) 再放一遍这张图:</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/02/PartyVotes-Presidents.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="PartyVotes-Presidents"></a></p><p>可以看到,在前 16 任总统的政治混乱之后(这段时期涵盖了历史学家所说的 <em>第一党派体系</em>——一直到昆西·亚当斯——和 <em>第二党派体系</em>——从杰克逊到皮尔斯),局面稳定下来,变成了清晰的共和党对民主党的对垒。本文覆盖的时期长达 36 年,从内战一直到 20 世纪拂晓——马克·吐温 (Mark Twain) 最早把这段时期称为「镀金时代 (The Gilded Age)」。<a href="#footnote-1-3429">1</a></p><p>这个时期的政治被历史学家称为**「第三党体制」(The Third Party System)**——在这个体制里,有共和党和民主党,听起来挺耳熟,但那两个党跟今天的这两个党几乎没什么相似之处。要说的话,镀金时代 (Gilded Age) 的共和党人可能跟今天的民主党人更有共同点,而当时的民主党人可能更像今天的共和党人(当然啦,界限很模糊,当时的两党各自都混合了今天两党的特征,而且还有一些今天完全不存在的特点,这就让当时和现在的比较有点像拿苹果比橘子)。</p><p>如图所示,镀金时代的共和党人——他们构成了南北战争中获胜的北方的大部分——在这个时代基本上占据了主导地位。</p><p>**2)<a href="https://en.wikipedia.org/wiki/Historical_rankings_of_Presidents_of_the_United_States" target="_blank" rel="noreferrer">这是这张图表</a>,显示了历史学家们对总统排名的综合结果。**当然,即便是综合排名也完全是主观的,绝非定论——但我相信这是给每位总统一个能反映学界大致共识的排名的最佳方式,反映他们互相之间的高下之分。那张表里的综合排名那一列,就是我在每位总统名字下面标的排名的来源。</p><p>那这篇文章里这一组的总统在排名里表现如何呢?这八位总统<em>没有一个</em>能挤进前 18 名。真是一帮好货色。</p><p><strong>3)现在是给自己复习一下「胡子时代」(Mustache Era) 的关键时刻。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/02/Mustache.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Mustache"></a></p><p>胡子时代是美国历史上前所未有的一段时期,在此期间,总统的胡子泛滥成灾。而在胡子时代之前或之后,再也没有出现过<em>任何一位</em>留胡子的总统。今天我们要讲的镀金时代几乎完全和胡子时代重合。<a href="#footnote-2-3429">2</a></p><p>现在,系好安全带,抓紧扶手,我要带你来一场旋风之旅,认识世界上最莫名其妙的八个男人。我们从 1865 年 4 月开始。南北战争刚刚结束,林肯刚刚被刺,整个国家一片混乱……</p><p><strong>17)安德鲁·约翰逊 (Andrew Johnson)</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2015/02/Johnson.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Johnson"></a></p><p><strong>任期:</strong> 1865 – 1869 <strong>生卒:</strong> 1808 – 1875 <strong>排名:</strong> 41/43</p><p><strong>留胡子?</strong> 没有。</p><p><strong>他的情况:</strong> 约翰逊出生在北卡罗来纳州一个超级贫穷的小木屋里,由单亲妈妈抚养长大,先当过裁缝学徒,然后走上了史上最刻板印象的从政阶梯——从市议员到市长到州众议院到州参议院到联邦国会到田纳西州州长到联邦参议员到副总统到总统。<a href="#footnote-3-3429">3</a> 真爽。约翰逊在这段史诗级旅程的顶点做了个奇怪的决定——用四年时间在最高一级台阶上当个混蛋,然后一路狼狈地摔回地面,给自己的传奇画上句号。他余生都在输掉一场场小选举,直到去世前四个月才终于赢下一个参议院席位。谈到晚年的这次参议院胜选,约翰逊感慨:「感谢上帝为我正名。」这话说得有点奇怪,因为今天他被公认为美国历史上第三糟糕的总统,而且基本上只作为 1998 年之前那个冷知识题——「唯一被弹劾过的美国总统是谁?」——的答案出现。</p><p><strong>他的总统任期:</strong> 1864 年(林肯第二任期之前),约翰逊被选为林肯的竞选搭档,因为他是个罕见的组合:一位来自南方(田纳西)的政客,林肯所在共和党的对手民主党人,却又狂热地支持联邦、反对分裂——这让他成为帮助林肯赢得选举、传递跨党派跨地域合作与国家团结信号的完美人选。赢得大选六周后,约翰逊和林肯以总统和副总统的身份进行了他们的第一次也是最后一次会面,因为那天晚上,林肯被枪杀了。</p><p>新任总统约翰逊接手的国家<em>刚刚</em>走出内战。硝烟尚未散尽,原本的计划是林肯用第二个任期为国家的未来做出无数关键决策。战争有了明确的赢家,一个政党——林肯的共和党——处于罕见的强势地位,这是一个重塑国家未来、终于摆脱奴隶制等自建国以来就困扰这个国家的历史冲突的难得机会。而林肯<em>真的</em>会是干这件事的最佳人选。</p><p>结果,这群斗志爆棚的共和党人突然被一个南方民主党人领着走,而这人事实证明并不怎么认同林肯为战后重建 (Reconstruction) 所规划的大部分内容。约翰逊接下来的四年里,拼尽全力妨碍共和党推进重大进展。共和党想对南方强硬,惩罚有名的邦联政客,并拒绝提供重建援助,除非南方各州同意给予新解放的奴隶平等权利和公民身份——但约翰逊否决了共和党国会试图通过的大多数议案,包括《民权法案》,理由是该法案赋予了「合众国每一个州的白人和黑人种族完全平等的地位」。他在给一位州长的信中写道:「这是一个属于白人的国家,天哪,只要我还是总统,它就将是一个属于白人的政府。」林肯听了肯定倍感欣慰。</p><p>鄙视约翰逊的共和党人在 1868 年成功弹劾了他,声称他在多个场合越过了总统的法定权限——在弹劾审判中,他们仅差一票就把他赶下了台。第二年,他在自己党内的初选中惨败,连竞选连任的机会都没捞到。</p><p>约翰逊的总统任期和布坎南 (Buchanan) 并列,是读起来最令人抓狂的。</p><p><strong>他可以吹嘘的事:</strong></p><ul><li>是唯一一位卸任后进入参议院任职的总统</li><li>阿拉斯加是约翰逊的功劳。他的国务卿威廉·西沃德 (William Seward) 以 720 万美元(相当于今天的 1.21 亿美元)从俄国把它买了下来。当时美国人认为这是一桩糟糕透顶的交易,这事儿有一段时间被叫做「西沃德的蠢事 (Seward&#39;s Folly)」。</li></ul><p><strong>他希望我们别记得的事:</strong></p><ul><li>我上面引用的那句白人至上主义名言</li><li>我目前研究前 24 位总统的过程中读到的绝对最搞笑的一件事:约翰逊在 1864 年他和林肯的就职典礼上,喝得<strong>烂醉</strong>就出现在会场,然后当着林肯和整个参议院议事厅震惊的目光,发表了一场冗长、语无伦次、醉醺醺的、彻彻底底的灾难性演讲。一位在场的参议员事后说:「我这辈子从没这么难堪过——要是能找到个洞,我一定钻进去藏起来。」之后约翰逊消失遁世了六个星期,以躲避公众的嘲笑。</li><li>他在当上副总统之前拥有大约九名奴隶,并且传言他和其中一位生了孩子。</li></ul><p><strong>他觉得郁闷的事:</strong></p><ul><li>据说他 60 岁生日那天办了一场几百个小孩子参加的派对,听起来是个无聊到极点的派对,而且绝对不是他自己的主意。</li><li>克林顿 (Clinton) 的弹劾案。直到 1998 年之前,大家关于他知道的<strong>唯一</strong>一件事就是他是唯一被弹劾过的总统。克林顿把约翰逊仅有的一项重大殊荣给抢走了。</li></ul><p><strong>其他值得一提的事实:</strong></p><ul><li>当过裁缝学徒之后,约翰逊一辈子都自己做衣服,连当总统的时候都不例外。</li><li>他长得跟汤米·李·琼斯 (Tommy Lee Jones) <a href="http://randomoverload.org/wp-content/uploads/2012/01/b293my-lee-jones-totally-looks-like-andrew-johnson.jpg" target="_blank" rel="noreferrer">简直</a><a href="http://cdn3.everyjoe.com/wp-content/gallery/celebrity-lookalikes/andrew-johnson-tommy-lee-jones.jpg" target="_blank" rel="noreferrer">一模一样</a>,笑死。</li><li>内战名将、下一任总统尤利西斯·S·格兰特 (Ulysses S. Grant) 在约翰逊任期内跟他闹得很僵,大概是因为约翰逊那套「试图把内战的所有成果一笔勾销」的做派。格兰特不许自己的孩子参加约翰逊的 60 岁生日派对,约翰逊则拒绝出席格兰特的就职典礼。</li><li>林肯被刺其实本来是同一晚三连暗杀计划的一部分。布斯 (Booth) 的两个同伙分别负责刺杀副总统约翰逊和国务卿苏厄德 (Seward)。刺杀苏厄德的行动差点成功,把他伤得很重。但据说负责杀约翰逊的乔治·阿茨罗特 (George Atzerodt) 压根没动手,因为他<a href="https://en.wikipedia.org/wiki/George_Atzerodt" target="_blank" rel="noreferrer">跑去喝醉了</a>。想象一下第二天布斯冲进阿茨罗特公寓质问到底怎么回事,阿茨罗特一脸懵:「啊?哦哦哦<em>操</em>……哦对……操我真的太抱歉了兄弟,完全给忘了。」画面感十足。</li></ul><p><strong>遗言:</strong> 中风后从椅子上摔下来时说的:「我的右半边瘫了。我不需要医生。我能挺过去。」他没挺过去。</p><p><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/2" target="_blank" rel="noreferrer">下一位(尤利西斯·S·格兰特)→</a></p><p><strong>全部页面:</strong></p><p><strong>安德鲁·约翰逊(以及引言)</strong><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/2" target="_blank" rel="noreferrer">尤利西斯·S·格兰特</a><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/3" target="_blank" rel="noreferrer">拉瑟福德·B·海斯</a><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/4" target="_blank" rel="noreferrer">詹姆斯·A·加菲尔德</a><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/5" target="_blank" rel="noreferrer">切斯特·A·阿瑟</a><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/6" target="_blank" rel="noreferrer">格罗弗·克利夫兰</a><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/7" target="_blank" rel="noreferrer">本杰明·哈里森</a><a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley/8" target="_blank" rel="noreferrer">威廉·麦金莱</a></p><hr><ol><li><p>这是一个讽刺性的名字,指的是这是一个被薄薄一层镀金掩盖着深层社会问题的时代。<a href="#note-1-3429">↩</a></p></li><li><p>顺便说一下,这不要和美国历史上的「胡须时代 (Beard Age)」搞混了,它和「小胡子时代 (Mustache Era)」有所重叠,但完全是另一个独立现象。从林肯到本杰明·哈里森 (Benjamin Harrison) 之间,一共有八位总统和 7.5 副胡须(林肯、格兰特和哈里森各一副,海斯和加菲尔德各两副,阿瑟半副)。和小胡子时代一样,胡须时代在历史上也是独一无二的事件——在此之前和之后,再也没有出现过留胡须的总统。<a href="#note-2-3429">↩</a></p></li><li><p>你们就习惯吧,我完全搞不清这些词哪些该大写哪些该小写。没有比这更让人困惑的了。<a href="#note-3-3429">↩</a></p></li></ol><p>页数: 1 <a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html/2" target="_blank" rel="noreferrer">2</a> <a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html/3" target="_blank" rel="noreferrer">3</a> <a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html/4" target="_blank" rel="noreferrer">4</a> <a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html/5" target="_blank" rel="noreferrer">5</a> <a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html/6" target="_blank" rel="noreferrer">6</a> <a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html/7" target="_blank" rel="noreferrer">7</a> <a href="https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html/8" target="_blank" rel="noreferrer">8</a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2015/02/american-presidents-johnson-mckinley.html&amp;description=The%20American%20Presidents%E2%80%94Johnson%20to%20McKinley" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p>',50)])])}const _=n(h,[["render",m]]);export{w as __pageData,_ as default};
